     1→export function shuffleArray<T>(array: T[]): T[] {
     2→	const shuffled = [...array];
     3→	for (let i = shuffled.length - 1; i > 0; i--) {
     4→		const j = Math.floor(Math.random() * (i + 1));
     5→		[shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]] as [T, T];
     6→	}
     7→	return shuffled;
     8→}
