    10→export function injectItemsRandomlyInFirstN<T>({
    11→	items,
    12→	targetArray,
    13→	firstN,
    14→}: {
    15→	items: T[];
    16→	targetArray: T[];
    17→	firstN: number;
    18→}): T[] {
    19→	if (items.length === 0) {
    20→		return [...targetArray];
    21→	}
    22→
    23→	const result = [...targetArray];
    24→	const numberOfItemsToInject = items.length;
    25→	const maxPosition = Math.max(firstN, numberOfItemsToInject);
    26→	const availablePositions = Array.from({ length: maxPosition }, (_, i) => i);
    27→	const shuffledPositions = shuffleArray(availablePositions);
    28→	const selectedPositions = shuffledPositions
    29→		.slice(0, numberOfItemsToInject)
    30→		.sort((a, b) => a - b);
    31→
    32→	for (let i = 0; i < numberOfItemsToInject; i++) {
    33→		const position = selectedPositions[i];
    34→		const item = items[i];
    35→		if (position !== undefined && item !== undefined) {
    36→			result.splice(position, 0, item);
    37→		}
    38→	}
    39→
